-- Completa catálogo de fuentes e indicadores para ejecución ETL total
-- sobre bases existentes, sin borrar datos.

ON CONFLICT (id) DO UPDATE
SET
    nombre = EXCLUDED.nombre,
    url_referencia = EXCLUDED.url_referencia,
    periodicidad = EXCLUDED.periodicidad,
    modulo_etl = EXCLUDED.modulo_etl,
    estado = EXCLUDED.estado,
    activo = TRUE;

SELECT setval('public.fuentes_datos_id_seq', (SELECT MAX(id) FROM public.fuentes_datos));

ON CONFLICT (clave) DO UPDATE
SET
    nombre = EXCLUDED.nombre,
    categoria = EXCLUDED.categoria,
    nivel_geografico = EXCLUDED.nivel_geografico,
    unidad = EXCLUDED.unidad,
    fuente_id = EXCLUDED.fuente_id,
    descripcion = EXCLUDED.descripcion,
    tipo_grafica = EXCLUDED.tipo_grafica,
    activo = TRUE;
